const workflowData = {
  workflow_name: 'AI Workflow Hub - Daily Data Aggregation',
  trigger_type: $node['Schedule Trigger'].json ? 'scheduled' : ($node['Manual Trigger'].json ? 'manual' : 'webhook'),
  started_at: new Date().toISOString(),
  status: 'running'
};

await $webhook.post({
  url: 'http://backend:8000/api/v1/webhooks/trigger-workflow',
  data: workflowData
});

return workflowData;

const notifications = await $webhook.post({
  url: 'http://backend:8000/api/v1/notify/slack',
  data: {
    message: `Workflow 'AI Workflow Hub' started execution.`
  }
});

return { notifications_sent: true };

const allData = $input.all();

const merged = {
  sources: [],
  data: {},
  fetched_at: new Date().toISOString()
};

for (const item of allData) {
  const source = item.json.source || item.json.url || 'unknown';
  merged.sources.push(source);
  merged.data[source] = item.json;
}

// Store raw data to backend
await $webhook.post({
  url: 'http://backend:8000/api/v1/webhooks/n8n/data-fetched',
  data: merged
});

return merged;

const data = $input.first().json;

// Remove null/undefined values
function cleanNulls(obj) {
  if (typeof obj !== 'object' || obj === null) return obj;
  if (Array.isArray(obj)) return obj.map(cleanNulls).filter(item => item !== null && item !== undefined);

  const cleaned = {};
  for (const [key, value] of Object.entries(obj)) {
    if (value !== null && value !== undefined) {
      cleaned[key] = cleanNulls(value);
    }
  }
  return cleaned;
}

// Convert timestamps to ISO
function convertTimestamps(obj) {
  if (typeof obj !== 'object' || obj === null) return obj;
  if (Array.isArray(obj)) return obj.map(convertTimestamps);

  const converted = {};
  for (const [key, value] of Object.entries(obj)) {
    if (typeof value === 'string' && /^\d{4}-\d{2}-\d{2}T/.test(value)) {
      converted[key] = new Date(value).toISOString();
    } else if (typeof value === 'number' && key.includes('timestamp') || key.includes('date')) {
      converted[key] = new Date(value * 1000).toISOString();
    } else {
      converted[key] = convertTimestamps(value);
    }
  }
  return converted;
}

let cleaned = cleanNulls(data);
cleaned = convertTimestamps(cleaned);
cleaned.processed_at = new Date().toISOString();

return cleaned;

const data = $input.first().json;

const prompt = `Summarize the following data concisely, highlighting key insights:

Sources: ${data.sources.join(', ')}

Data: ${JSON.stringify(data.data, null, 2).substring(0, 3000)}`;

return { prompt, data };

const aiOutput = $input.first().json;

await $webhook.post({
  url: 'http://backend:8000/api/v1/webhooks/n8n/ai-output',
  data: {
    execution_id: $node['Initialize Execution'].json.execution_id,
    prompt_type: 'summarize',
    model: 'gpt-4o',
    input_tokens: aiOutput.usage?.prompt_tokens || 0,
    output_tokens: aiOutput.usage?.completion_tokens || 0,
    output_content: aiOutput.message?.content || '',
    input_summary: $node['Prepare AI Prompt'].json.prompt?.substring(0, 500) || ''
  }
});

return aiOutput;

const aiContent = $input.first().json.message?.content || '';
const mergedData = $node['Merge Data'].json;

const now = new Date();
const row = [
  now.toISOString().split('T')[0],
  mergedData.sources?.join('; ') || 'multiple',
  aiContent.substring(0, 200),
  aiContent.substring(0, 500),
  'completed'
];

return { row, aiContent };

const row = $input.first().json.row;

await $webhook.post({
  url: 'http://backend:8000/api/v1/sheets/append',
  data: row
});

return { appended: true };

const aiContent = $input.first().json.aiContent;
const sources = $node['Merge Data'].json.sources;

const emailBody = `
<h2>AI Workflow Hub - Daily Report</h2>
<p><strong>Date:</strong> ${new Date().toISOString().split('T')[0]}</p>
<p><strong>Data Sources:</strong> ${sources.join(', ')}</p>
<h3>AI Summary</h3>
<p>${aiContent.replace(/\n/g, '<br>')}</p>
<h3>Top Insights</h3>
<ul>
<li>Data aggregated from ${sources.length} sources</li>
<li>Processed and analyzed using GPT-4o</li>
<li>All results stored in database</li>
</ul>
<p><strong>Status:</strong> Completed</p>
`;

await $webhook.post({
  url: 'http://backend:8000/api/v1/notify/email',
  data: {
    to: $env.REPORT_EMAIL || 'user@example.com',
    subject: `AI Workflow Report - ${new Date().toISOString().split('T')[0]}`,
    body: emailBody
  }
});

return { email_sent: true };

const message = `
*AI Workflow Hub - Daily Execution Summary*
\n*Status:* Completed ✅\n*Date:* ${new Date().toISOString().split('T')[0]}\n*Sources:* ${$node['Merge Data'].json.sources?.join(', ') || 'N/A'}\n\nWorkflow has completed successfully. All data has been processed, stored, and reported.`;

await $webhook.post({
  url: 'http://backend:8000/api/v1/notify/slack',
  data: { message }
});

return { slack_notified: true };

const executionData = $node['Initialize Execution'].json;

await $webhook.post({
  url: 'http://backend:8000/api/v1/webhooks/n8n/workflow-completed',
  data: {
    execution_id: executionData.execution_id,
    workflow_name: 'AI Workflow Hub - Daily Data Aggregation',
    status: 'completed',
    trigger_type: executionData.trigger_type,
    duration_ms: new Date() - new Date(executionData.started_at),
    completed_at: new Date().toISOString()
  }
});

return { completed: true };
